    "summary": "IQAC information.",
    "sourceFile": "iqac.php",
    "html": "<div class=\"container-fluid bg-light\">\r\n  <div class=\"container\">\r\n    <div class=\"row py-4\">\r\n      <div class=\"col-md-12\">\r\n        <h2 class=\"divider line one-line-primary\">\r\n          <span class=\"mx-2\">IQAC</span>\r\n        </h2>\r\n        <h3>Objectives:</h3>\r\n        <ol type=\"1\">\r\n          <li>\r\n            To prepare students for careers in the industry and pursue research\r\n            in all the branches of computing field through effective teaching\r\n            learning process.\r\n          </li>\r\n\r\n          <li>\r\n            To strengthen the industry institute by providing up-to-date\r\n            programs.\r\n          </li>\r\n\r\n          <li>\r\n            To imbibe amongst the students ethical usage of technical knowledge\r\n            beneficial to the society.\r\n          </li>\r\n\r\n          <li>\r\n            Well designed mechanism for supervision, control and monitoring.\r\n          </li>\r\n\r\n          <li>\r\n            Active involvement of students in quality assurance mechanism.\r\n          </li>\r\n\r\n          <li>\r\n            Positive response to the students feedback on curriculum, teaching,\r\n            infrastructure and support services.\r\n          </li>\r\n        </ol>\r\n      </div>\r\n    </div>\r\n    <div class=\"row py-4\">\r\n      <div class=\"col-md-12\">\r\n        <h3 class=\"divider line one-line-primary\">\r\n          <span class=\"mx-2\">Committee</span>\r\n        </h3>\r\n        <div class=\"card border border-secondary shadow\">\r\n          <div class=\"card-body\">\r\n            <table class=\"table table-hover\" style=\"text-align : center;\">\r\n              <thead style=\"text-align : center;\">\r\n                <tr>\r\n                  <th style=\"text-align : center;\">No</th>\r\n                  <th style=\"text-align : center;\">Name</th>\r\n                  <th style=\"text-align : center;\">Post</th>\r\n                </tr>\r\n              </thead>\r\n              <tbody>\r\n                <tr class=\"info\">\r\n                  <td>1</td>\r\n                  <td>Dr. Suhasini Vijaykumar</td>\r\n                  <td>Chairperson</td>\r\n                </tr>\r\n                <tr class=\"info\">\r\n                  <td>2</td>\r\n                  <td>Ms. Uttara Athawale</td>\r\n                  <td>Member - Coordinator</td>\r\n                </tr>\r\n                <tr class=\"info\">\r\n                  <td>3</td>\r\n                  <td>Ms. Prathibha Deshmukh</td>\r\n                  <td>Member</td>\r\n                </tr>\r\n                <tr class=\"info\">\r\n                  <td>4</td>\r\n                  <td>Mr. Manish Dubey</td>\r\n                  <td>Member</td>\r\n                </tr>\r\n                <tr class=\"info\">\r\n                  <td>5</td>\r\n                  <td>Dr. Kirti Muley</td>\r\n                  <td>Member</td>\r\n                </tr>\r\n                <tr class=\"info\">\r\n                  <td>6</td>\r\n                  <td>Ms.Sudeshna Roy</td>\r\n                  <td>Member</td>\r\n                </tr>\r\n\r\n                <tr class=\"info\">\r\n                  <td>8</td>\r\n                  <td>Mr. Amol Ghatage</td>\r\n                  <td>Senior administrative officer</td>\r\n                </tr>\r\n                <tr class=\"info\">\r\n                  <td>9</td>\r\n                  <td>Mr. Devdas Ghadage</td>\r\n                  <td>Senior administrative officer</td>\r\n                </tr>\r\n                <tr class=\"info\">\r\n                  <td>10</td>\r\n                  <td>Mr. Raj Varhsney</td>\r\n                  <td>Employeers -e2Seve</td>\r\n                </tr>\r\n                <tr class=\"info\">\r\n                  <td>11</td>\r\n                  <td>Mr. Deepak Prakash</td>\r\n                  <td>Alumini</td>\r\n                </tr>\r\n              </tbody>\r\n            </table>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    <div class=\"row py-4\">\r\n      <div class=\"col-md-12\">\r\n        \r\n      </div>\r\n    </div>\r\n  </div>\r\n</div>"
