    "sourceFile": "metric-1-1-main.php",
    "html": "<div class=\"container-fluid bg-light\">\n  <div class=\"container\">\n    <div class=\"row py-4\">\n      <div class=\"col-md-12\">\n        <h2 class=\"divider line one-line-primary\">\n          <span class=\"mx-2\">NAAC- CRITERIA</span>\n        </h2>\n                \n      </div>\n    </div>\n\n    <h5 class=\"divider line one-line-primary\"><i class=\"fas fa-arrow-right text-primary\"></i> <span class=\"mx-2\">Metric 1.1 </span><i class=\"fas fa-arrow-left text-primary\"></i></center>\n\n        </h5>\n\n    \n     <section class=\"py-2\">\n        <div class=\"container\">\n            <div class=\"row\">\n                <div class=\"col-md-12\">\n                    <div class=\"card h-100 text-center shadow border border-primary\">\n                        <div class=\"card-body\">\n                \n    <h5> <cite>The Institution ensures effective curriculum planning and delivery through a well-planned and documented process including Academic calendar and conduct of continuous internal Assessment</cite></h5>            \n   \n    \n                    </div>\n                </div>\n            </div>\n        </div>\n    </section>\n\n\n    <div class=\"row py-4\">\n      <div class=\"col-md-12\">\n       \n        <div class=\"card border border-secondary shadow\">\n          <div class=\"card-body\">\n            <table class=\"table table-hover\" style=\"text-align : left;\">\n              <thead style=\"text-align : left;\">\n                <tr>\n                  <th style=\"text-align : left;\">Sr. No</th>\n                  <th style=\"text-align : left;\">Particulars</th>\n                  <th style=\"text-align : left;\">File Name</th>\n                </tr>\n              </thead>\n              <tbody>\n\n\n\n                <tr class=\"info\">\n                  <td>1</td>\n                  <td>List of  Supporting Documents </td>\n                  <td>  <a target=\"_blank\" href=>   VIEW DOCUMENT</a></td>\n                </tr>\n                <tr class=\"info\">\n                  <td>2</td>\n                  <td>List of Additional Documents</td>\n                  <td>  <a target=\"_blank\" href=>   VIEW DOCUMENT</a></td>\n                </tr>\n               \n                \n\n               \n              </tbody>\n            </table>\n          </div>\n        </div>\n      </div>\n    </div>\n    <div class=\"row py-4\">\n      <div class=\"col-md-12\">\n        \n      </div>\n    </div>\n  </div>\n</div>"
