  "/courses/pgdbm": {
    "kind": "content",
    "path": "/courses/pgdbm",
    "canonicalPath": "/courses/pgdbm",
    "title": "PGDBM",
    "section": "Programmes",
    "summary": "PGDBM course details.",
    "sourceFile": "course_pgdbm.php",
    "html": "<div class=\"container-fluid bg-light\">\r\n  <div class=\"container\">\r\n    <section class=\"py-5\">\r\n      <h2 class=\"divider line one-line-primary\">\r\n        <span class=\"mx-2\">PGDBM</span>\r\n      </h2>\r\n      <div class=\"row\">\r\n        <div class=\"col-md-4\">\r\n          <div class=\"card border border-primary shadow\">\r\n            <div\r\n              class=\"card-header text-center text-white font-weight-bold bg-primary\"\r\n            >\r\n              Specializations\r\n            </div>\r\n            <div class=\"card-body\" style=\"font-size: 20px\">\r\n              <ul>\r\n                <li>Finance</li>\r\n                <li>Human Resources</li>\r\n                <li>Marketing</li>\r\n                <li>Systems</li>\r\n                <li>Operations</li>\r\n                <li>Pharma</li>\r\n                <li>International Business</li>\r\n              </ul>\r\n            </div>\r\n          </div>\r\n        </div>\r\n        <div class=\"col-md-8\">\r\n          <div class=\"card border border-primary shadow\">\r\n            <div\r\n              class=\"card-header text-center text-white font-weight-bold bg-primary\"\r\n            >\r\n              Eligibility\r\n            </div>\r\n            <div class=\"card-body\">\r\n              <ul style=\"font-size: 20px\">\r\n                <li>\r\n                  A graduate from any statutory university with a minimum of 50%\r\n                  marks (45% for SC/ST) at graduation level.\r\n                </li>\r\n                <li>\r\n                  Student appearing for final year examinations can also apply,\r\n                  but their admission will be subject to obtaining a minimum of\r\n                  50% marks (45% for SC/ST) at qualifying examination.\r\n                </li>\r\n                <li>Diploma holders are not eligible.</li>\r\n                <li>Intake: 60 students.</li>\r\n              </ul>\r\n            </div>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </section>\r\n\r\n    <section class=\"py-5\">\r\n      <h2 class=\"divider line one-line-primary\">\r\n        <span class=\"mx-2\">Programme Fees</span>\r\n      </h2>\r\n      <div class=\"text-center\">\r\n        <div class=\"card border border-primary shadow\">\r\n          <div class=\"card-body\">\r\n            <h5 class=\"text-center px-5\">\r\n              The programme fees is Rs. 4,50,000 for 2 years.\r\n            </h5>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    </section>\r\n\r\n    <section class=\"py-5\">\r\n      <h2 class=\"divider line one-line-primary\">\r\n        <span class=\"mx-2\">Contact Details</span>\r\n      </h2>\r\n      <div class=\"card border border-primary shadow\">\r\n        <div class=\"card-body\">\r\n          <h5 class=\"text-center px-5\">\r\n            Bharati Vidyapeeth's Institute of Management & Information\r\n            Technology, Sector 8 , C.B.D. Belapur,Navi Mumbai 400614.\r\n          </h5>\r\n        </div>\r\n      </div>\r\n    </section>\r\n  </div>\r\n</div>"
  },
