  "/research/code-of-ethics": {
    "kind": "content",
    "path": "/research/code-of-ethics",
    "canonicalPath": "/research/code-of-ethics",
    "title": "Code of Ethics",
    "section": "Research",
    "summary": "Ethics and code of conduct related to academic and research work.",
    "sourceFile": "code_ethics.php",
    "html": "<div class=\"bg-light\">\n    <div class=\"container text-justify\">\n  <section class=\"py-5\">\n   \n      \n      \n        <h5 class=\"divider line one-line-primary\">\n          <i class=\"fas fa-arrow-right text-primary\"></i\n          ><span class=\"mx-2\">Code of Ethics in Research Activities\n</span\n          ><i class=\"fas fa-arrow-left text-primary\"></i>\n        </h5>\n\n\n\n<div class=\"row py-4\">\n        <div class=\"card border border-primary shadow\">\n          <div class=\"card-body\">\n            <div class=\"row\">\n              <div class=\"col-md-12\">\n                <h3 class=\"text-center text-primary\"></h3>\n              </div>\n            </div>\n            <br />\n            <div class=\"row\">\n             \n                <p class=\"text-justify\">\n                  <i class=\"fas fa-circle text-primary\"></i>\n                  The Code of Ethics in Research is general principles of ethical conduct to guide scholars toward\nthe highest ideals of scholarly research. Our institute has developed a “Code of Ethics” for\nresearch which is to be followed by our faculty and students. \n                </p>\n              \n              \n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  </section>\n  \n <section class=\"py-1\">\n     \n     <div class=\"container\">\n         <div class=\"row\">\n             \n             <div class=\"card border border-primary shadow-lg\">\n                 <div class=\"card-body\">\n                     <table class=\"table table-hover\" style=\"font-size: 16px;\">\n          \n          <tbody>\n            <tr>\n              <td class=\"font-weight-bold\" style=\"text-align: center\">\n                <span class=\"text-primary\"><i class=\"fas fa-check\"></i></span>\n               \n              </td>\n              <td>\n                Conduct all research activities in accordance with the accepted standards in an ethical manner.\n              </td>\n            </tr>\n            <tr>\n              <td class=\"font-weight-bold\" style=\"text-align: center\">\n                <span class=\"text-primary\"><i class=\"fas fa-check\"></i></span>\n               \n              </td>\n              <td>\n                All collaborative research projects shall have a documented Memorandum of\nUnderstanding, specifying the terms and scope of collaboration, duly signed by all\ncollaborators. \n              </td>\n            </tr>\n            <tr>\n              <td class=\"font-weight-bold\" style=\"text-align: center\">\n                <span class=\"text-primary\"><i class=\"fas fa-check\"></i></span>\n                \n              </td>\n              <td>\n                Conflicts of Interest should be resolved in a transparent and fair manner.\n              </td>\n            </tr>\n            <tr>\n              <td class=\"font-weight-bold\" style=\"text-align: center\">\n                <span class=\"text-primary\"><i class=\"fas fa-check\"></i></span>\n                \n              </td>\n              <td>\n                Appropriate attribute and credit must be given to others for their accomplishments and research results which we may have utilized in our own research.\n              </td>\n            </tr>\n            <tr>\n              <td class=\"font-weight-bold\" style=\"text-align: center\">\n                <span class=\"text-primary\"><i class=\"fas fa-check\"></i></span>\n               \n              </td>\n              <td>\n                Cite clearly all sources of information and data that we use which are not the results of our own research. Give proper acknowledgment and credit to resource/funding sources\nof our research.\n              </td>\n            </tr>\n            <tr>\n              <td class=\"font-weight-bold\" style=\"text-align: center\">\n                <span class=\"text-primary\"><i class=\"fas fa-check\"></i></span>\n               \n              </td>\n              <td>\n                Researchers shall refer to relevant findings of other researchers, to the best of their knowledge, in their reviews and duly acknowledge them when these works are used or\nreferred to in research analysis. \n              </td>\n            </tr>\n            <tr>\n              <td class=\"font-weight-bold\" style=\"text-align: center\">\n                <span class=\"text-primary\"><i class=\"fas fa-check\"></i></span>\n               \n              </td>\n              <td>\n                Ensure that only the correct data, information, and research results shall be submitted in journals, conferences, and reports.\n              </td>\n            </tr>\n            <tr>\n              <td class=\"font-weight-bold\" style=\"text-align: center\">\n                <span class=\"text-primary\"><i class=\"fas fa-check\"></i></span>\n               \n              </td>\n              <td>\n                The researchers shall take adequate care to ensure that their research reports, knowingly or unknowingly, are not copies of reports published earlier by other workers. Not to\nplagiarize, even if the other work or data source is cited occasionally\n              </td>\n            </tr>\n            <tr>\n              <td class=\"font-weight-bold\" style=\"text-align: center\">\n                <span class=\"text-primary\"><i class=\"fas fa-check\"></i></span>\n                \n              </td>\n              <td>\n                The researchers shall try their best to bring their research findings into public domain by appropriate timely publication(s) for the furtherance of the research process\n              </td>\n            </tr>\n            <tr>\n              <td class=\"font-weight-bold\" style=\"text-align: center\">\n                <span class=\"text-primary\"><i class=\"fas fa-check\"></i></span>\n               \n              </td>\n              <td>\n                Observe safety practices and protection of the Environment in all our research activities.\n              </td>\n            </tr>\n            \n             \n          </tbody>\n        </table>\n                 </div>\n             </div>\n             \n     \n    </div>\n     </div>\n   \n    \n    \n  </section>\n</div>\n</div>"
  },
