    "html": "<div class=\"container-fluid bg-light\">\n  <div class=\"py-2\">\n    <div class=\"container\">\n      <h3 class=\"divider line one-line-primary\">\n        <i class=\"fas fa-star text-primary\"></i\n        ><span style=\"margin-left: 1%; margin-right:1%;\"\n          >Glimpses of BVIMIT</span\n        ><i class=\"fas fa-star text-primary\"></i>\n      </h3>\n     \n          \n            \n     <div class=\"card border border-primary shadow\">\n\n         \n            <div class=\"card-body text-justify lead\">\n             BVIMIT conducts several Co-curricular and Extra Curricular activities for the students. ‘Glimpses of BVIMIT’ is an annual magazine which highlights all these activities conducted and performedby the students in an academic year.  \n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <div class=\"container-fluid bg-light\" style=\"min-height: 800px;\">\n  <div class=\"py-2\">\n    <div class=\"container\">\n      \n\n      <div class=\"row\">\n        \n    \n      <div class=\"col-md-3\">\n          <a \n          target=\"_blank\"\n          href=\"/legacy/pdfs/Glipses_2024.pdf\">\n            <div class=\"card\">\n              \n              <img\n                class=\"card-img-top\"\n                src=\"/legacy/pdfs/Thumbnails/glimpses24.PNG\"\n                alt=\"\"\n              />\n              <div class=\"card-body\">\n                Glimpses of BVIMIT 2023-2024\n              </div>\n            </div>\n          </a>\n        </div>\n    \n         <div class=\"col-md-3\">\n          <a \n          target=\"_blank\"\n          href=\"/legacy/pdfs/glimpses 2022-23.pdf\">\n            <div class=\"card\">\n              \n              <img\n                class=\"card-img-top\"\n                src=\"/legacy/pdfs/Thumbnails/GLIMPSES22-23.PNG\"\n                alt=\"\"\n              />\n              <div class=\"card-body\">\n                Glimpses of BVIMIT 2022-2023\n              </div>\n            </div>\n          </a>\n        </div>\n    \n    \n    \n     <div class=\"col-md-3\">\n          <a \n          target=\"_blank\"\n          href=\"/legacy/pdfs/Glimpses 2021-2022.pdf\">\n            <div class=\"card\">\n              \n              <img\n                class=\"card-img-top\"\n                src=\"/legacy/pdfs/Thumbnails/glimpses2021-22.PNG\"\n                alt=\"\"\n              />\n              <div class=\"card-body\">\n                Glimpses of BVIMIT 2021-2022\n              </div>\n            </div>\n          </a>\n        </div>\n    \n    \n    <div class=\"col-md-3\">\n          <a \n          target=\"_blank\"\n          href=\"/legacy/pdfs/Glimpses 2020-2021.pdf\">\n            <div class=\"card\">\n              \n              <img\n                class=\"card-img-top\"\n                src=\"/legacy/pdfs/Thumbnails/g20-21.PNG\"\n                alt=\"\"\n              />\n              <div class=\"card-body\">\n                Glimpses of BVIMIT 2020-2021\n              </div>\n            </div>\n          </a>\n        </div>\n        \n        <div class=\"col-md-3\">\n          <a \n          target=\"_blank\"\n          href=\"/legacy/pdfs/Glimpses 2019-20.pdf\">\n            <div class=\"card\">\n              \n              <img\n                class=\"card-img-top\"\n                src=\"/legacy/pdfs/Thumbnails/glimpse19-20.PNG\"\n                alt=\"\"\n              />\n              <div class=\"card-body\">\n                Glimpses of BVIMIT 2019-2020\n              </div>\n            </div>\n          </a>\n        </div>\n    \n        <div class=\"col-md-3\">\n          <a \n          target=\"_blank\"\n          href=\"/legacy/pdfs/Glimpses 2018-19.pdf\">\n            <div class=\"card\">\n              \n              <img\n                class=\"card-img-top\"\n                src=\"/legacy/pdfs/Thumbnails/glimpses2018-19.PNG\"\n                alt=\"\"\n              />\n              <div class=\"card-body\">\n                Glimpses of BVIMIT 2018-2019\n              </div>\n            </div>\n          </a>\n        </div>\n        <div class=\"col-md-3\">\n          <a \n          target=\"_blank\"\n          href=\"/legacy/pdfs/Glimpses 2017-18.pdf\">\n            <div class=\"card\">\n              \n              <img\n                class=\"card-img-top\"\n                src=\"/legacy/pdfs/Thumbnails/glimpse2017-18.PNG\"\n                alt=\"\"\n              />\n              <div class=\"card-body\">\n                Glimpses of BVIMIT 2017-2018\n              </div>\n            </div>\n          </a>\n        </div>\n        <div class=\"col-md-3\">\n          <a \n          target=\"_blank\"\n          href=\"/legacy/pdfs/Glimpses 2016-17.pdf\">\n            <div class=\"card\">\n              \n              <img\n                class=\"card-img-top\"\n                src=\"/legacy/pdfs/Thumbnails/glimpses2016-17.PNG\"\n                alt=\"\"\n              />\n              <div class=\"card-body\">\n               Glimpses of BVIMIT 2016-2017\n              </div>\n            </div>\n          </a>\n        </div>\n       \n        \n         \n         \n      </div> \n      </div>"
