    "html": "<div class=\"container-fluid bg-light\">\n  <div class=\"py-2\">\n    <div class=\"container\">\n      <h3 class=\"divider line one-line-primary\">\n        <i class=\"fas fa-star text-primary\"></i\n        ><span style=\"margin-left: 1%; margin-right:1%;\"\n          >STUDENT HANDBOOK</span\n        ><i class=\"fas fa-star text-primary\"></i>\n      </h3>\n     \n          \n            \n     \n<div class=\"card border border-primary shadow\">\n         \n            <div class=\"card-body text-justify lead\">\n             Student Handbook is an annual publication. This handbook provides students with information on many facets of college life such as plicies, procedures, instituteand services.   \n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <div class=\"container-fluid bg-light\" style=\"min-height: 800px;\">\n  <div class=\"py-2\">\n    <div class=\"container\">\n      \n\n      <div class=\"row\">\n        \n    \n    \n     <div class=\"col-md-3\">\n          <a\n          target=\"_blank\"\n          href=\"/legacy/pdfs/BVIMIT STUDENT HANDBOOK 2023-2024 (2).pdf\">\n            <div class=\"card\">\n              \n              <img\n                class=\"card-img-top\"\n                src=\"/legacy/pdfs/Thumbnails/sh23-24.PNG\"\n                alt=\"\"\n              />\n              <div class=\"card-body\">\n                 Student Handbook 2023-24\n              </div>\n            </div>\n          </a>\n        </div>\n    \n    \n    \n     <div class=\"col-md-3\">\n          <a\n          target=\"_blank\"\n          href=\"/legacy/pdfs/Student Handbook2022-2023.pdf\">\n            <div class=\"card\">\n              \n              <img\n                class=\"card-img-top\"\n                src=\"/legacy/pdfs/Thumbnails/s22-23.PNG\"\n                alt=\"\"\n              />\n              <div class=\"card-body\">\n                 Student Handbook 2022-23\n              </div>\n            </div>\n          </a>\n        </div>\n    \n    \n    <div class=\"col-md-3\">\n          <a\n          target=\"_blank\"\n          href=\"/legacy/pdfs/Final NBA Student Handbook 2021-2022 20 Oct.pdf\">\n            <div class=\"card\">\n              \n              <img\n                class=\"card-img-top\"\n                src=\"/legacy/pdfs/Thumbnails/STUDENT_HANDBOOK21-22.PNG\"\n                alt=\"\"\n              />\n              <div class=\"card-body\">\n                 Student Handbook 2021-22\n              </div>\n            </div>\n          </a>\n        </div>\n        \n        <div class=\"col-md-3\">\n          <a\n          target=\"_blank\"\n          href=\"/legacy/pdfs/Final NBA Student Handbook 2020-2021 20 Oct.pdf\">\n            <div class=\"card\">\n              \n              <img\n                class=\"card-img-top\"\n                src=\"/legacy/pdfs/Thumbnails/STUDENT_HANDBOOK20-21.PNG\"\n                alt=\"\"\n              />\n              <div class=\"card-body\">\n                 Student Handbook 2020-21\n              </div>\n            </div>\n          </a>\n        </div>\n    \n     <div class=\"col-md-3\">\n          <a\n          target=\"_blank\"\n          href=\"/legacy/pdfs/19-20_handbook.pdf\">\n            <div class=\"card\">\n              \n              <img\n                class=\"card-img-top\"\n                src=\"/legacy/pdfs/Thumbnails/sh2020.PNG\"\n                alt=\"\"\n              />\n              <div class=\"card-body\">\n                 Student Handbook 2019-20\n              </div>\n            </div>\n          </a>\n        </div>\n    \n        <div class=\"col-md-3\">\n          <a \n          target=\"_blank\"\n          href=\"/legacy/pdfs/STUDENT_HANDBOOK 2018-2019.pdf\">\n            <div class=\"card\">\n              \n              <img\n                class=\"card-img-top\"\n                src=\"/legacy/pdfs/Thumbnails/sh2018-19.PNG\"\n                alt=\"\"\n              />\n              <div class=\"card-body\">\n                 Student Handbook 2018-19\n              </div>\n            </div>\n          </a>\n        </div>\n        <div class=\"col-md-3\">\n          <a \n           target=\"_blank\"\n          href=\"/legacy/pdfs/STUDENT_HANDBOOK 2017-2018.pdf\">\n            <div class=\"card\">\n              \n              <img\n                class=\"card-img-top\"\n                src=\"/legacy/pdfs/Thumbnails/sh2017-18.PNG\"\n                alt=\"\"\n              />\n              <div class=\"card-body\">\n               Student Handbook 2017-18\n              </div>\n            </div>\n          </a>\n        </div>"
